func TestProcessEntityUpdate_TripleIndexing(t *testing.T) {
	tests := []struct {
		name          string
		triples       []message.Triple
		wantOutgoing  bool
		wantIncoming  bool
		wantAlias     bool
		wantPredicate int // Count of predicates indexed
	}{
		{
			name: "relationship triple indexes outgoing and incoming",
			triples: []message.Triple{
				{
					Subject:   "c360.platform.robotics.mav1.drone.001",
					Predicate: "robotics.assigned.mission",
					Object:    "c360.platform.robotics.mav1.mission.001",
				},
			},
			wantOutgoing:  true,
			wantIncoming:  true,
			wantAlias:     false,
			wantPredicate: 1,
		},
		{
			name: "literal triple indexes only predicate",
			triples: []message.Triple{
				{
					Subject:   "c360.platform.robotics.mav1.drone.001",
					Predicate: "robotics.status.armed",
					Object:    true,
				},
			},
			wantOutgoing:  false,
			wantIncoming:  false,
			wantAlias:     false,
			wantPredicate: 1,
		},
		{
			name: "alias triple indexes alias",
			triples: []message.Triple{
				{
					Subject:   "c360.platform.robotics.mav1.drone.001",
					Predicate: "core.identity.alias",
					Object:    "drone-001",
				},
			},
			wantOutgoing:  false,
			wantIncoming:  false,
			wantAlias:     true,
			wantPredicate: 1,
		},
		{
			name: "multiple triples index appropriately",
			triples: []message.Triple{
				{
					Subject:   "c360.platform.robotics.mav1.drone.001",
					Predicate: "robotics.assigned.mission",
					Object:    "c360.platform.robotics.mav1.mission.001",
				},
				{
					Subject:   "c360.platform.robotics.mav1.drone.001",
					Predicate: "robotics.status.armed",
					Object:    true,
				},
				{
					Subject:   "c360.platform.robotics.mav1.drone.001",
					Predicate: "core.identity.alias",
					Object:    "drone-001",
				},
			},
			wantOutgoing:  true,
			wantIncoming:  true,
			wantAlias:     true,
			wantPredicate: 3,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			comp := createTestComponentWithMockKV(t)

			entityID := "c360.platform.robotics.mav1.drone.001"
			state := graph.EntityState{
				Triples: tt.triples,
			}

			// Create mock entry
			data, err := json.Marshal(state)
			require.NoError(t, err)

			entry := &mockKVEntry{data: data}
			comp.processEntityUpdate(context.Background(), entry)

			// Verify outgoing index
			outgoing := outgoingMock(comp)
			outgoing.mu.Lock()
			_, hasOutgoing := outgoing.data[entityID]
			outgoing.mu.Unlock()
			assert.Equal(t, tt.wantOutgoing, hasOutgoing, "outgoing index presence mismatch")

			// Verify incoming index
			if tt.wantIncoming {
				incoming := incomingMock(comp)
				incoming.mu.Lock()
				hasIncoming := len(incoming.data) > 0
				incoming.mu.Unlock()
				assert.True(t, hasIncoming, "incoming index should have entries")
			}

			// Verify alias index
			if tt.wantAlias {
				alias := aliasMock(comp)
				alias.mu.Lock()
				hasAlias := len(alias.data) > 0
				alias.mu.Unlock()
				assert.True(t, hasAlias, "alias index should have entries")
			}

			// Verify predicate index
			predicate := predicateMock(comp)
			predicate.mu.Lock()
			predicateCount := len(predicate.data)
			predicate.mu.Unlock()
			assert.Equal(t, tt.wantPredicate, predicateCount, "predicate count mismatch")
		})
	}
}

func TestProcessEntityUpdate_RelationshipDetection(t *testing.T) {
	tests := []struct {
		name           string
		triple         message.Triple
		isRelationship bool
	}{
		{
			name: "entity ID as object is relationship",
			triple: message.Triple{
				Subject:   "c360.platform.robotics.mav1.drone.001",
				Predicate: "robotics.assigned.mission",
				Object:    "c360.platform.robotics.mav1.mission.001",
			},
			isRelationship: true,
		},
		{
			name: "string literal is not relationship",
			triple: message.Triple{
				Subject:   "c360.platform.robotics.mav1.drone.001",
				Predicate: "robotics.description",
				Object:    "A quadcopter drone",
			},
			isRelationship: false,
		},
		{
			name: "boolean literal is not relationship",
			triple: message.Triple{
				Subject:   "c360.platform.robotics.mav1.drone.001",
				Predicate: "robotics.status.armed",
				Object:    true,
			},
			isRelationship: false,
		},
		{
			name: "numeric literal is not relationship",
			triple: message.Triple{
				Subject:   "c360.platform.robotics.mav1.drone.001",
				Predicate: "robotics.battery.level",
				Object:    85.5,
			},
			isRelationship: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			comp := createTestComponentWithMockKV(t)

			entityID := "c360.platform.robotics.mav1.drone.001"
			state := graph.EntityState{
				Triples: []message.Triple{tt.triple},
			}

			// Create mock entry
			data, err := json.Marshal(state)
			require.NoError(t, err)

			entry := &mockKVEntry{data: data}
			comp.processEntityUpdate(context.Background(), entry)

			// Check if outgoing/incoming indexes were populated
			outgoing := outgoingMock(comp)
			outgoing.mu.Lock()
			_, hasOutgoing := outgoing.data[entityID]
			outgoing.mu.Unlock()

			assert.Equal(t, tt.isRelationship, hasOutgoing,
				"relationship detection mismatch: expected %v, got %v", tt.isRelationship, hasOutgoing)
		})
	}
}

