func TestUpdateIndex_UpdatesLastActivity(t *testing.T) {
	comp := createTestComponentWithMockKV(t)
	ctx := context.Background()

	initialActivity := comp.lastActivity.Load().(time.Time)

	time.Sleep(10 * time.Millisecond)

	err := comp.UpdateOutgoingIndex(ctx, "entity", "target", "predicate")
	require.NoError(t, err)

	updatedActivity := comp.lastActivity.Load().(time.Time)
	assert.True(t, updatedActivity.After(initialActivity), "last activity should update")
}
